// ---- Guide lines (Experiment 2b: CSS stacked-gradient) ---------------------
//
// @replit/codemirror-indentation-markers' technique: one `--to-guides`
// custom property per line, a comma-joined list of repeating-linear-
// gradient layers (one per active ancestor depth), consumed by a single
// `::before` — O(1) DOM nodes regardless of depth, no JS pixel measurement,
// no overlay layer (contrast Experiment 2a's measured overlay divs).
//
// CONFIRMED STRUCTURAL LIMITATION, not just an unhandled edge case: this
// only works on lines whose own box is never shifted by `margin` — i.e.
// `to-decor-block` lines (headings/paragraphs) only. `padding-left` (used
// for those lines) shifts content but never the box itself, so a block
// line's own box always starts at the same x regardless of its depth,
// exactly like the code-indentation use case this technique was built for
// (indentation there is rendered via literal leading whitespace, so the
// line's box never moves either). But `to-decor-atom`/`to-decor-list`
// lines use `margin-left` (Experiment 1's own, deliberate fix for the
// "padding never moves the box" bug) — margin DOES shift the box itself,
// so any background painted inside it is clipped to a canvas that starts
// to the right of a shallower ancestor's own column. CSS backgrounds are
// always clipped to their own element's box; no `background-position`
// value paints further left than the box's own left edge. So a bridging
// guide can never render on an atom or list-item line via this technique
// — confirmed by the box model, not assumed; verify this holds in the real
// vault before trusting it (ground rule #3). This is a real difference
// from Experiment 2a's overlay, which paints in a layer entirely outside
// `.cm-content` and is unaffected by any one line's own box/shift.
function guideLayer(depth: number): string {
  const unit = 'var(--to-decor-unit, 1.5rem)';
  return (
    `repeating-linear-gradient(to right, var(--text-faint) 0 1px, transparent 1px ${unit}) ` +
    `calc(${depth} * ${unit}) 0 / ${unit} 100% no-repeat`
  );
}

function guideBackground(guideDepths: readonly number[]): string {
  return guideDepths.map(guideLayer).join(', ');
}

function lineDecoration(fact: LineDecorationFact, guide: LineGuideFact): Decoration {
  if (fact.isListItem) {
    return Decoration.line({
      class: 'to-decor-list',
      attributes: { style: `--to-supp-depth: ${fact.supplementalDepth}` },
    });
  }
  const styles = [`--to-depth: ${fact.depth}`];
  let cls = fact.isAtom ? 'to-decor-atom' : 'to-decor-block';
  // PROBE: testing whether an atom line CAN render a guide if the pseudo's
  // own box is widened leftward (not clipped to the line's own margin-
  // shifted box) instead of matching it exactly.
  if (guide.guideDepths.length > 0) {
    cls += ' to-decor-guides';
    styles.push(`--to-guides: ${guideBackground(guide.guideDepths)}`);
    if (fact.isAtom) styles.push(`--to-own-shift: ${fact.depth}`);
  }
  return Decoration.line({ class: cls, attributes: { style: styles.join('; ') } });
}

