describe('probe: does callout ::before even get generated at all', function () {
  before(async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
  });

  it('checks ::before content + all matching CSS rules on the callout wrapper', async function () {
    const md = ['# Section', '', '> [!note] Title', '> body', ''].join('\n');
    await h.createNote('Scratch/probe-callout2.md', md);
    if (!(await h.isOutlineMode('Scratch/probe-callout2.md'))) {
      await h.toggleOutlineMode();
      await h.waitForNotice('Outline mode on');
      await h.dismissNotices();
    }
    await browser.pause(200);

    const info = await browser.executeObsidian(({ app, obsidian }) => {
      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
      const cm = (view.editor as any).cm;
      const el = cm.contentDOM.querySelector('.cm-embed-block.cm-callout') as HTMLElement;
      if (!el) return { error: 'not found' };
      const beforeStyle = getComputedStyle(el, '::before');
      // Find matching CSS rules for ::before on this element across all stylesheets.
      const matchingRules: string[] = [];
      for (const sheet of Array.from(document.styleSheets)) {
        let rules: CSSRuleList;
        try { rules = sheet.cssRules; } catch { continue; }
        for (const rule of Array.from(rules)) {
          if (rule instanceof CSSStyleRule && rule.selectorText && rule.selectorText.includes('::before')) {
            try {
              if (el.matches(rule.selectorText.replace('::before', ''))) {
                matchingRules.push(`${rule.selectorText} { ${rule.style.cssText} } [${sheet.href ?? 'inline'}]`);
              }
            } catch {}
          }
        }
      }
      return {
        cls: el.className,
        content: beforeStyle.content,
        display: beforeStyle.display,
        position: beforeStyle.position,
        backgroundImage: beforeStyle.backgroundImage,
        matchingRules,
      };
    });
    console.log(JSON.stringify(info, null, 2));
  });
});
