  it('checks element.style.contain directly + searches stylesheets for contain rules', async function () {
    const md = ['# Section', '', '> [!note] Title', '> body', ''].join('\n');
    await h.createNote('Scratch/probe-inline-check.md', md);
    if (!(await h.isOutlineMode('Scratch/probe-inline-check.md'))) {
      await h.toggleOutlineMode();
      await h.waitForNotice('Outline mode on');
      await h.dismissNotices();
    }
    await browser.pause(200);

    const info = await browser.executeObsidian(({ app, obsidian }) => {
      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
      const cm = (view.editor as any).cm;
      const el = cm.contentDOM.querySelector('.cm-embed-block.cm-callout') as HTMLElement;
      const inlineContain = el.style.getPropertyValue('contain');
      const inlinePriority = el.style.getPropertyPriority('contain');
      const rules: string[] = [];
      for (const sheet of Array.from(document.styleSheets)) {
        let cssRules: CSSRuleList;
        try { cssRules = sheet.cssRules; } catch { continue; }
        for (const rule of Array.from(cssRules)) {
          if (rule instanceof CSSStyleRule && rule.style.getPropertyValue('contain')) {
            try {
              if (el.matches(rule.selectorText)) {
                rules.push(`${rule.selectorText} => contain: ${rule.style.getPropertyValue('contain')} ${rule.style.getPropertyPriority('contain')} [${sheet.href ?? sheet.ownerNode?.id ?? 'inline-sheet'}]`);
              }
            } catch {}
          }
        }
      }
      return { inlineContain, inlinePriority, styleAttr: el.getAttribute('style'), matchingRules: rules };
    });
    console.log(JSON.stringify(info, null, 2));
  });
});
