import * as fsp from 'node:fs/promises';
import * as path from 'node:path';
import { browser, expect } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

const DIR = path.join(process.cwd(), '.obsidian-cache', 'probe-screenshots');

describe('probe: Minimal theme check', function () {
  before(async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
    await fsp.mkdir(DIR, { recursive: true });
  });

  it('switches to Minimal theme and screenshots decorations-mixed', async function () {
    await browser.executeObsidian(async ({ app }) => {
      // @ts-ignore
      await app.customCss.setTheme('Minimal');
    });
    await browser.pause(300);

    const md = [
      '# Top', '', '## Mid', '', '- item', '  - nested item', '',
      'Parent para.', '- Child para as list item.', '',
      '```js', 'code line', '```', '',
    ].join('\n');
    await h.createNote('Scratch/probe-minimal-theme.md', md);
    if (!(await h.isOutlineMode('Scratch/probe-minimal-theme.md'))) {
      await h.toggleOutlineMode();
      await h.waitForNotice('Outline mode on');
      await h.dismissNotices();
    }
    await browser.pause(200);
    await h.screenshotFull(DIR, 'minimal-theme-mixed-light');

    const info = await browser.executeObsidian(({ app, obsidian }) => {
      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
      const cm = (view.editor as any).cm;
      const lines = cm.contentDOM.querySelectorAll(':scope > .cm-line');
      return Array.from(lines).map((el, i) => ({
        i,
        cls: (el as HTMLElement).className,
        marginLeft: getComputedStyle(el as HTMLElement).marginLeft,
        paddingLeft: getComputedStyle(el as HTMLElement).paddingLeft,
      }));
    });
    console.log(JSON.stringify(info, null, 2));

    // Switch back
    await browser.executeObsidian(async ({ app }) => {
      // @ts-ignore
      await app.customCss.setTheme('');
    });
  });
});
EOF
